pub fn verify_jwt(token: &str, config: &JwtConfig) -> Result<UserInfo, JwtError> {
    if config.allowed_algorithms.is_empty() {
        return Err(JwtError::ConfigurationError);
    }

    let header = decode_header(token).map_err(|_| JwtError::InvalidToken)?;

    if !config.allowed_algorithms.contains(&header.alg) {
        return Err(JwtError::UnsupportedAlgorithm);
    }

    let decoding_key = config
        .keys
        .get(&header.alg)
        .ok_or(JwtError::ConfigurationError)?;

    let mut validation = Validation::new(header.alg);
    validation.validate_exp = true;
    validation.validate_nbf = true;
    validation.leeway = 0;

    if let Some(ref issuer) = config.required_issuer {
        validation.set_issuer(&[issuer]);
    }

    if let Some(ref audience) = config.required_audience {
        validation.set_audience(&[audience]);
    }

    let token_data = decode::<Claims>(token, decoding_key, &validation)
        .map_err(|e| match e.kind() {
            jsonwebtoken::errors::ErrorKind::ExpiredSignature => JwtError::ExpiredToken,
            jsonwebtoken::errors::ErrorKind::InvalidSignature => JwtError::InvalidSignature,
            jsonwebtoken::errors::ErrorKind::InvalidIssuer => JwtError::InvalidIssuer,
            jsonwebtoken::errors::ErrorKind::InvalidAudience => JwtError::InvalidAudience,
            _ => JwtError::InvalidToken,
        })?;

    let claims = token_data.claims;

    if claims.sub.is_empty() {
        return Err(JwtError::MissingClaims);
    }

    let current_time = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap()
        .as_secs() as usize;

    if claims.exp <= current_time {
        return Err(JwtError::ExpiredToken);
    }

    Ok(UserInfo {
        user_id: claims.sub,
        email: claims.email,
        name: claims.name,
        roles: claims.roles.unwrap_or_default(),
        issuer: claims.iss,
    })
}

pub fn extract_bearer_token(authorization_header: &str) -> Option<&str> {
    let parts: Vec<&str> = authorization_header.splitn(2, ' ').collect();
    if parts.len() == 2 && parts[0].eq_ignore_ascii_case("bearer") {
        Some(parts[1])
    } else {
        None
    }
}

